ROLE_PERMISSIONS = {
    'admin': ['read', 'write', 'delete', 'manage_users'],
    'editor': ['read', 'write'],
    'viewer': ['read']
}

class PermissionService:
    def __init__(self, auth_service):
        self.auth = auth_service

    def check_permission(self, session_id, permission):
        user = self.auth.get_user_for_session(session_id)
        if user is None:
            return False
        user_perms = ROLE_PERMISSIONS.get(user.role)
        return permission in user_perms

    def get_permissions(self, session_id):
        user = self.auth.get_user_for_session(session_id)
        if user is None:
            return []
        return ROLE_PERMISSIONS.get(user.role)

    def require_permission(self, session_id, permission):
        if not self.check_permission(session_id, permission):
            raise PermissionError(f'Missing permission: {permission}')
        return True
